import React, { useState } from "react";
import logo from "./logo.png";

function App() {
  const [currentPage, setCurrentPage] = useState("home");

  // Function to handle navigation
  const navigateTo = (page) => {
    setCurrentPage(page);
  };

  // Home page content
  const Home = () => (
    <div style={styles.homeContainer}>
      {/* Left Section: Logo */}
      <div style={styles.logoSection}>
        <img src={logo} alt="Logo" style={styles.logo} />
      </div>

      {}
      <div style={styles.descriptionSection}>
        <nav style={styles.navbar}>
          <button style={styles.navButton} onClick={() => navigateTo("home")}>
            Home
          </button>
          <button style={styles.navButton} onClick={() => navigateTo("about")}>
            About
          </button>
          <button style={styles.navButton} onClick={() => navigateTo("contact")}>
            Contact
          </button>
          <button style={styles.navButton} onClick={() => navigateTo("login")}>
            Login
          </button>
        </nav>
        <div style={styles.descriptionContent}>
          <h1>Welcome to SoundWake</h1>
          <p>
            Our goal is to promote independent artists worldwide. Discover new underground music, create playlists, and share your
            experience with your friends.
          </p>
        </div>
      </div>
    </div>
  );

  const Login = () => {
    const [activeForm, setActiveForm] = useState("login");
    const [formData, setFormData] = useState({
      email: "",
      password: "",
      confirmPassword: "",
    });

    const handleFormSwitch = (form) => {
      setActiveForm(form);
      setFormData({ email: "", password: "", confirmPassword: "" });
    };

    const handleSubmit = (event) => {
      event.preventDefault();
      if (
        activeForm === "signup" &&
        formData.password !== formData.confirmPassword
      ) {
        alert("Passwords do not match");
        return;
      }
      alert(
        `${activeForm === "login" ? "Logged In" : "Account Created"} Successfully!`
      );
    };

    const handleInputChange = (e) => {
      const { name, value } = e.target;
      setFormData((prev) => ({ ...prev, [name]: value }));
    };

    return (
      <div className="login-container">
        {/* Login Form Section */}
        <div className="login-form-container">
          <h1>{activeForm === "login" ? "Login" : "Create Account"}</h1>
          <form onSubmit={handleSubmit} className="form">
            <input
              type="email"
              name="email"
              placeholder="Email"
              value={formData.email}
              onChange={handleInputChange}
              className="input"
              required
            />
            <input
              type="password"
              name="password"
              placeholder="Password"
              value={formData.password}
              onChange={handleInputChange}
              className="input"
              required
            />
            {activeForm === "signup" && (
              <input
                type="password"
                name="confirmPassword"
                placeholder="Confirm Password"
                value={formData.confirmPassword}
                onChange={handleInputChange}
                className="input"
                required
              />
            )}
            <button type="submit" className="button">
              {activeForm === "login" ? "Login" : "Sign Up"}
            </button>
          </form>
          <p className="toggle-text">
            {activeForm === "login"
              ? "Don't have an account?"
              : "Already have an account?"}{" "}
            <button
              type="button"
              onClick={() =>
                handleFormSwitch(activeForm === "login" ? "signup" : "login")
              }
              className="toggle-button"
            >
              {activeForm === "login" ? "Create Account" : "Login"}
            </button>
          </p>
          <button
            className="back-home-button"
            onClick={() => navigateTo("home")}
          >
            Back to Home
          </button>
        </div>
      </div>
    );
  };

  return (
    <div>
      {currentPage === "home" && <Home />}
      {currentPage === "login" && <Login />}
    </div>
  );
}

export default App;
